"use client";

import { useEffect, useMemo, useState } from "react";
import {
  allDomains,
  allSkills,
  buildCustomExam,
  type CustomExamSpec,
  type Difficulty,
  type Exam,
} from "@/lib/marketing-tests/exams";
import {
  Badge,
  Button,
  Card,
  Input,
  Slider,
  Textarea,
} from "@/components/marketing/ui";

const PRESET_KEY = "marketing-hub:custom-exam-presets";
const LEVELS = ["associate", "professional", "expert"] as const;
type Level = (typeof LEVELS)[number];
const DIFFICULTIES: Difficulty[] = [1 as Difficulty, 2 as Difficulty, 3 as Difficulty];

function toggleInArray<T>(arr: T[] | undefined, item: T): T[] {
  const a = arr ?? [];
  return a.includes(item) ? a.filter((x) => x !== item) : [...a, item];
}

function loadPresets(): CustomExamSpec[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = localStorage.getItem(PRESET_KEY);
    return raw ? (JSON.parse(raw) as CustomExamSpec[]) : [];
  } catch {
    return [];
  }
}

function savePresets(list: CustomExamSpec[]) {
  try {
    localStorage.setItem(PRESET_KEY, JSON.stringify(list));
  } catch {
    /* ignore */
  }
}

function ToggleButton({
  active,
  onClick,
  children,
}: {
  active: boolean;
  onClick: () => void;
  children: React.ReactNode;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      className={`px-3 py-1.5 rounded-md text-sm font-medium border transition-colors ${
        active
          ? "border-indigo-500 bg-indigo-50 text-indigo-700"
          : "border-gray-200 text-gray-600 hover:border-indigo-300"
      }`}
    >
      {children}
    </button>
  );
}

export function CustomExamBuilder({
  onStart,
  onBack,
}: {
  onStart: (exam: Exam) => void;
  onBack: () => void;
}) {
  const [spec, setSpec] = useState<CustomExamSpec>({
    title: "",
    description: "",
    passingScore: 75,
    durationMinutes: 15,
    maxQuestions: 10,
  });
  const [presets, setPresets] = useState<CustomExamSpec[]>([]);
  const [savedMsg, setSavedMsg] = useState(false);

  useEffect(() => {
    setPresets(loadPresets());
  }, []);

  const domains = useMemo(() => allDomains(), []);
  const skills = useMemo(() => allSkills(), []);

  const hasTitle = spec.title.trim().length > 0;
  const preview = useMemo(
    () => (hasTitle ? buildCustomExam(spec) : null),
    [spec, hasTitle],
  );
  const previewCount = preview ? preview.questions.length : 0;
  const canStart = hasTitle && previewCount > 0;

  function patch(p: Partial<CustomExamSpec>) {
    setSpec((s) => ({ ...s, ...p }));
  }

  function handleSavePreset() {
    if (!hasTitle) return;
    const next = [...presets, spec];
    setPresets(next);
    savePresets(next);
    setSavedMsg(true);
    window.setTimeout(() => setSavedMsg(false), 2000);
  }

  function handleLoadPreset(preset: CustomExamSpec) {
    setSpec(preset);
  }

  function handleStartPreset(preset: CustomExamSpec) {
    onStart(buildCustomExam(preset));
  }

  function handleDeletePreset(idx: number) {
    const next = presets.filter((_, i) => i !== idx);
    setPresets(next);
    savePresets(next);
  }

  function handleStart() {
    if (!canStart) return;
    onStart(buildCustomExam(spec));
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Custom Exam Builder</h2>
          <p className="text-sm text-gray-500">
            Assemble a custom exam from the existing question pool.
          </p>
        </div>
        <Button variant="outline" onClick={onBack}>
          Back
        </Button>
      </div>

      <Card className="p-6 space-y-5">
        <div className="space-y-1.5">
          <label className="text-sm font-medium text-gray-700">Title</label>
          <Input
            value={spec.title}
            onChange={(e) => patch({ title: e.target.value })}
            placeholder="e.g. Senior Backend Screening"
            invalid={!hasTitle && spec.title.length > 0}
          />
        </div>

        <div className="space-y-1.5">
          <label className="text-sm font-medium text-gray-700">Description</label>
          <Textarea
            value={spec.description}
            onChange={(e) => patch({ description: e.target.value })}
            placeholder="Short description shown to candidates"
            rows={3}
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
          <div className="space-y-1.5">
            <label className="text-sm font-medium text-gray-700">
              Passing score: <span className="font-semibold">{spec.passingScore}</span>
            </label>
            <Slider
              value={spec.passingScore}
              onValueChange={(v) => patch({ passingScore: v })}
              min={50}
              max={95}
              step={1}
            />
          </div>

          <div className="space-y-1.5">
            <label className="text-sm font-medium text-gray-700">
              Max questions: <span className="font-semibold">{spec.maxQuestions}</span>
            </label>
            <Slider
              value={spec.maxQuestions}
              onValueChange={(v) => patch({ maxQuestions: v })}
              min={5}
              max={30}
              step={1}
            />
          </div>
        </div>

        <div className="space-y-1.5">
          <label className="text-sm font-medium text-gray-700">
            Duration (minutes)
          </label>
          <Input
            type="number"
            value={spec.durationMinutes}
            onChange={(e) =>
              patch({ durationMinutes: Number(e.target.value) || 0 })
            }
            min={1}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-medium text-gray-700">Domains</label>
          <div className="flex flex-wrap gap-2">
            {domains.map((d) => (
              <ToggleButton
                key={d}
                active={spec.domains?.includes(d) ?? false}
                onClick={() =>
                  patch({ domains: toggleInArray(spec.domains, d) })
                }
              >
                {d}
              </ToggleButton>
            ))}
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-medium text-gray-700">Levels</label>
          <div className="flex flex-wrap gap-2">
            {LEVELS.map((lvl) => (
              <ToggleButton
                key={lvl}
                active={spec.levels?.includes(lvl) ?? false}
                onClick={() =>
                  patch({ levels: toggleInArray(spec.levels, lvl) })
                }
              >
                {lvl}
              </ToggleButton>
            ))}
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-medium text-gray-700">Difficulties</label>
          <div className="flex flex-wrap gap-2">
            {DIFFICULTIES.map((d) => (
              <ToggleButton
                key={d}
                active={spec.difficulties?.includes(d) ?? false}
                onClick={() =>
                  patch({ difficulties: toggleInArray(spec.difficulties, d) })
                }
              >
                {`Level ${d}`}
              </ToggleButton>
            ))}
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-medium text-gray-700">Skills</label>
          <div className="flex flex-wrap gap-2">
            {skills.map((s) => (
              <ToggleButton
                key={s}
                active={spec.skills?.includes(s) ?? false}
                onClick={() =>
                  patch({ skills: toggleInArray(spec.skills, s) })
                }
              >
                {s}
              </ToggleButton>
            ))}
          </div>
        </div>

        <div className="flex items-center justify-between pt-2 border-t border-gray-100">
          <div className="text-sm text-gray-600">
            {hasTitle ? (
              <Badge variant="secondary">
                {previewCount} question{previewCount === 1 ? "" : "s"} match
              </Badge>
            ) : (
              <span className="text-gray-400">Enter a title to preview</span>
            )}
            {savedMsg && (
              <span className="ml-3 text-green-600 font-medium">Saved!</span>
            )}
          </div>
          <div className="flex gap-2">
            <Button variant="outline" onClick={handleSavePreset} disabled={!hasTitle}>
              Save preset
            </Button>
            <Button onClick={handleStart} disabled={!canStart}>
              Start exam
            </Button>
          </div>
        </div>
      </Card>

      {presets.length > 0 && (
        <Card className="p-6 space-y-3">
          <h3 className="text-lg font-semibold text-gray-900">Saved presets</h3>
          <ul className="divide-y divide-gray-100">
            {presets.map((p, idx) => {
              const count = buildCustomExam(p).questions.length;
              return (
                <li
                  key={`${p.title}-${idx}`}
                  className="py-3 flex items-center justify-between gap-3"
                >
                  <div className="min-w-0">
                    <div className="font-medium text-gray-800 truncate">
                      {p.title}
                    </div>
                    <div className="text-xs text-gray-500">
                      {count} question{count === 1 ? "" : "s"} match
                    </div>
                  </div>
                  <div className="flex gap-2 shrink-0">
                    <Button variant="outline" onClick={() => handleLoadPreset(p)}>
                      Load
                    </Button>
                    <Button variant="secondary" onClick={() => handleStartPreset(p)}>
                      Start
                    </Button>
                    <Button
                      variant="destructive"
                      onClick={() => handleDeletePreset(idx)}
                    >
                      Delete
                    </Button>
                  </div>
                </li>
              );
            })}
          </ul>
        </Card>
      )}
    </div>
  );
}
